#include <stdio.h>
#include <string.h>
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    char lang[100][100];
    int points[100];
    for (int i = 0; i < n; i++) {
        scanf("%s %d", lang[i], &points[i]);
    }
    for (int i = 0; i < m; i++) {
        char query[100];
        scanf("%s", query);
        int maxPoints = 0;
        for (int j = 0; j < n; j++) {
            if (strcmp(query, lang[j]) == 0) {
                maxPoints = points[j];
                break;
            }
        }
        printf("%d\n", maxPoints);
    }
    return 0;
}

