code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let [n, m] = lines[0].split(' ').map(Number);
    let langPoints = {};
    for (let i = 1; i <= n; i++) {
        let [lang, points] = lines[i].split(' ');
        langPoints[lang] = Number(points);
    }
    for (let i = n + 1; i <= n + m; i++) {
        let query = lines[i];
        console.log(langPoints[query] || 0);
    }
});

